export const 鎮宅經求 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    // 符頭：連珠桿（四圈貫桿）＋桿二＋短桿
    線(p => p.M(X(0.95), Z(1.0)).L(X(6.1), Z(0.92)));
    圈(0.6, 1.0);
    圈(1.8, 0.98);
    圈(3.5, 0.95);
    圈(6.4, 0.9);
    線(p => p.M(X(0.95), Z(2.4)).L(X(6.1), Z(2.32)));
    圈(0.6, 2.4);
    圈(6.4, 2.3);
    線(p => p.M(X(0.95), Z(3.8)).L(X(2.2), Z(3.75)));
    圈(0.6, 3.8);
    圈(2.5, 3.72);
    圈(6.5, 3.7);
    // 厂寬桁垂圈
    線(p => p.M(X(0.7), Z(4.7)).L(X(6.5), Z(4.6)), 0.42);
    線(p => p.M(X(6.6), Z(4.65)).L(X(6.65), Z(5.5)));
    圈(6.7, 5.9);
    // 雙柱目梯疊
    const 梯 = (x0, x1, z0, 層, 步) => {
        線(p => p.M(X(x0), Z(z0)).L(X(x0), Z(z0 + 層 * 步)));
        線(p => p.M(X(x1), Z(z0 - 0.05)).L(X(x1), Z(z0 + 層 * 步 - 0.05)));
        for (let i = 0; i <= 層; i++)
            線(p => p.M(X(x0), Z(z0 + i * 步)).L(X(x1), Z(z0 + i * 步 - 0.05)));
    };
    梯(0.7, 3.3, 5.8, 6, 1.78);
    梯(3.7, 6.4, 5.8, 5, 2.14);
    // 己曲雙環底＋右軌
    線(p => p.M(X(1.0), Z(16.9))
        .C(X(0.6), Z(17.4), X(0.8), Z(18.0), X(1.5), Z(18.05))
        .C(X(2.1), Z(18.1), X(2.3), Z(17.6), X(1.9), Z(17.3))
        .C(X(1.5), Z(17.9), X(1.7), Z(18.5), X(2.5), Z(18.5))
        .L(X(3.3), Z(18.45)), 0.36);
    線(p => p.M(X(6.4), Z(16.6)).C(X(6.5), Z(17.4), X(6.4), Z(18.1), X(6.0), Z(18.6)));
};
